151	// ResolvedLadder returns the escalation ladder for the named profile. If
152	// ProfileLadders contains an entry for profile, that wins. Otherwise falls
153	// back to the deprecated ProfilePriority for the default profile only. If
154	// neither is set, returns the shipped FEAT-006 profile ladder.
155	func (r *RoutingConfig) ResolvedLadder(profile string) []string {
156		if profile == "" {
157			profile = "default"
158		}
159		if r == nil {
160			if ladder, ok := defaultProfileLadders[profile]; ok {
161				return append([]string(nil), ladder...)
162			}
163			return append([]string(nil), defaultProfileLadders["default"]...)
164		}
165		if r.ProfileLadders != nil {
166			if ladder, ok := r.ProfileLadders[profile]; ok && len(ladder) > 0 {
167				return append([]string(nil), ladder...)
168			}
169		}
170		if profile == "default" && len(r.ProfilePriority) > 0 {
171			return append([]string(nil), r.ProfilePriority...)
172		}
173		if ladder, ok := defaultProfileLadders[profile]; ok {
174			return append([]string(nil), ladder...)
175		}
176		return append([]string(nil), defaultProfileLadders["default"]...)
177	}
