// Package evidence provides shared primitives for assembling LLM prompts
// from bounded evidence sources. Every prompt-building call site in DDx
// must use these primitives so that no prompt has unbounded size.
//
// FEAT-022 §1 / §1a. Stage A1.
package evidence

// Built-in default caps. These are intentionally permissive on land
// (FEAT-022 Non-Functional / Backward compatibility) so existing
// behavior does not change. Stage F telemetry informs later tightening.
const (
	DefaultMaxPromptBytes       = 4 * 1024 * 1024 // 4 MiB
	DefaultMaxInlinedFileBytes  = 512 * 1024      // 512 KiB
	DefaultMaxDiffBytes         = 2 * 1024 * 1024 // 2 MiB
	DefaultMaxGoverningDocBytes = 256 * 1024      // 256 KiB
)

// Caps is the resolved byte-cap set used by an evidence-assembly call site.
// All caps are byte-based (FEAT-022 Non-Functional / Byte-based enforcement).
type Caps struct {
	MaxPromptBytes       int
	MaxInlinedFileBytes  int
	MaxDiffBytes         int
	MaxGoverningDocBytes int
}

// DefaultCaps returns the built-in conservative defaults.
func DefaultCaps() Caps {
	return Caps{
		MaxPromptBytes:       DefaultMaxPromptBytes,
		MaxInlinedFileBytes:  DefaultMaxInlinedFileBytes,
		MaxDiffBytes:         DefaultMaxDiffBytes,
		MaxGoverningDocBytes: DefaultMaxGoverningDocBytes,
	}
}

// CapsOverride is the partial-override shape that .ddx/config.yaml
// expresses. A nil pointer means "fall through to the next layer".
type CapsOverride struct {
	MaxPromptBytes       *int
	MaxInlinedFileBytes  *int
	MaxDiffBytes         *int
	MaxGoverningDocBytes *int
}

// Apply layers an override onto a Caps value, returning the resolved Caps.
// Nil fields in the override leave the corresponding cap unchanged.
func (c Caps) Apply(o CapsOverride) Caps {
	if o.MaxPromptBytes != nil {
		c.MaxPromptBytes = *o.MaxPromptBytes
	}
	if o.MaxInlinedFileBytes != nil {
		c.MaxInlinedFileBytes = *o.MaxInlinedFileBytes
	}
	if o.MaxDiffBytes != nil {
		c.MaxDiffBytes = *o.MaxDiffBytes
	}
	if o.MaxGoverningDocBytes != nil {
		c.MaxGoverningDocBytes = *o.MaxGoverningDocBytes
	}
	return c
}

// ResolveCaps resolves the effective caps for an invocation given a
// project-wide override and an optional per-harness override. Precedence
// (low → high): defaults < project-wide < per-harness.
//
// harness == "" or absence in perHarness means no per-harness layer.
// A missing project override is expressed as a zero-value CapsOverride.
func ResolveCaps(project CapsOverride, perHarness map[string]CapsOverride, harness string) Caps {
	caps := DefaultCaps().Apply(project)
	if harness != "" && perHarness != nil {
		if h, ok := perHarness[harness]; ok {
			caps = caps.Apply(h)
		}
	}
	return caps
}

package evidence

// TruncationMarker is the canonical string downstream parsers check for to
// detect that a section was clamped by an evidence primitive. Equality
// against this constant is the contract; do not redefine locally.
const TruncationMarker = "\n\n[…truncated by ddx evidence cap…]\n"

// Pre-dispatch overflow outcome classes (FEAT-022 §7, §12). These are the
// strings the reviewer and grader paths emit when bounded assembly still
// exceeds MaxPromptBytes.
const (
	OutcomeReviewContextOverflow  = "review-error: context_overflow"
	OutcomeCompareContextOverflow = "compare-error: context_overflow"
)

package evidence

import (
	"errors"
	"fmt"
	"io"
	"os"
)

// ErrOversize is returned by hard-fail readers (e.g. user-supplied prompt
// files, FEAT-022 §8). Callers compare with errors.Is to surface a
// distinct error class to the user.
var ErrOversize = errors.New("evidence: input exceeds cap")

// OversizeError carries the input-source name, observed size, and cap
// for actionable error messages (FEAT-022 Non-Functional / Failure mode
// clarity).
type OversizeError struct {
	Source        string
	ObservedBytes int64
	CapBytes      int
}

func (e *OversizeError) Error() string {
	return fmt.Sprintf("evidence: %s exceeds cap: observed %d bytes, cap %d bytes",
		e.Source, e.ObservedBytes, e.CapBytes)
}

func (e *OversizeError) Unwrap() error { return ErrOversize }

// ReadFileClamped reads up to max+1 bytes from path. If the file fits
// within max it returns (content, false, len(content), nil). If the file
// exceeds max it returns the first max bytes plus truncated=true and
// originalBytes set to the on-disk size (as observed via os.Stat). The
// implementation does not fully load oversize files into memory
// (FEAT-022 Non-Functional / Performance).
func ReadFileClamped(path string, max int) (content []byte, truncated bool, originalBytes int64, err error) {
	if max < 0 {
		return nil, false, 0, fmt.Errorf("evidence: negative cap %d", max)
	}
	// nolint:gosec // path is supplied by callers that have already validated it.
	f, err := os.Open(path) // os.ReadFile equivalent — bounded read below.
	if err != nil {
		return nil, false, 0, err
	}
	defer f.Close()

	st, err := f.Stat()
	if err != nil {
		return nil, false, 0, err
	}
	originalBytes = st.Size()

	// Read max+1 bytes so we can detect overflow without loading the whole file.
	buf := make([]byte, max+1)
	n, readErr := io.ReadFull(f, buf)
	if readErr != nil && readErr != io.EOF && readErr != io.ErrUnexpectedEOF {
		return nil, false, originalBytes, readErr
	}

	if n > max {
		return buf[:max], true, originalBytes, nil
	}
	return buf[:n], false, int64(n), nil
}

// ReadFileHardFail reads path and returns *OversizeError (wrapping
// ErrOversize) if the file exceeds max. Used for user-supplied prompt
// files where silent truncation is forbidden (FEAT-022 §8).
func ReadFileHardFail(path string, max int, source string) ([]byte, error) {
	content, truncated, originalBytes, err := ReadFileClamped(path, max)
	if err != nil {
		return nil, err
	}
	if truncated {
		return nil, &OversizeError{
			Source:        source,
			ObservedBytes: originalBytes,
			CapBytes:      max,
		}
	}
	return content, nil
}

package evidence

// ClampOutput trims s to at most max bytes. When trimming occurs the
// returned text ends with TruncationMarker (the marker is included in
// the returned bytes; the length of the returned string may exceed max
// only by the marker length when max is too small to fit even the
// marker, in which case ClampOutput returns the bare marker truncated
// to max bytes). originalBytes is len(s) before clamping.
//
// FEAT-022 §1 (clamped text output, canonical truncation marker).
func ClampOutput(s string, max int) (clamped string, truncated bool, originalBytes int) {
	originalBytes = len(s)
	if max < 0 {
		max = 0
	}
	if originalBytes <= max {
		return s, false, originalBytes
	}
	// Reserve room for the marker. If max is smaller than the marker,
	// return a marker-only string truncated to max bytes (still flagged
	// truncated so the caller never silently drops content).
	if max <= len(TruncationMarker) {
		return TruncationMarker[:max], true, originalBytes
	}
	keep := max - len(TruncationMarker)
	return s[:keep] + TruncationMarker, true, originalBytes
}

package evidence

import "strings"

// EvidenceAssemblySection is the per-section telemetry record produced by
// the evidence-assembly call sites and consumed by Stages C1, C2, and F
// (FEAT-022 §15). The shape is a contract — downstream stages decode this
// without re-deriving field names.
type EvidenceAssemblySection struct {
	Name             string   `json:"name"`
	BytesIncluded    int      `json:"bytes_included"`
	BytesOmitted     int      `json:"bytes_omitted"`
	TruncationReason string   `json:"truncation_reason"`
	SelectedItems    []string `json:"selected_items"`
	OmittedItems     []string `json:"omitted_items"`
}

// SectionInput is one candidate section handed to FitSections, in
// caller-determined priority order (highest priority first).
type SectionInput struct {
	Name    string
	Content string
	// MinFloor, when true, marks this section as part of the minimum
	// evidence floor (FEAT-022 §5 items 1-2). Floor sections are always
	// included; if even the floor exceeds budget FitSections still
	// emits them but reports the overall overflow via the returned
	// TotalBytes vs budget comparison left to the caller.
	MinFloor bool
	// PerSectionCap, if non-zero, additionally clamps this section to
	// at most this many bytes (using ClampOutput) before budgeting.
	PerSectionCap int
}

// FitResult is the outcome of FitSections.
type FitResult struct {
	Included   []SectionInput
	Omitted    []SectionInput
	TotalBytes int
	Sections   []EvidenceAssemblySection
}

// FitSections selects sections to include under a total byte budget,
// in priority order. Floor sections are always included. Non-floor
// sections are added in order while their content fits the remaining
// budget; sections that don't fit are recorded as omitted.
//
// Default behavior is line-based and type-agnostic (FEAT-022 §1):
// when a section's PerSectionCap is non-zero, content is clamped to
// that cap before budgeting. Markdown-aware extraction is handled by
// callers that need it; this primitive does not parse content.
func FitSections(sections []SectionInput, budget int) FitResult {
	if budget < 0 {
		budget = 0
	}
	res := FitResult{
		Sections: make([]EvidenceAssemblySection, 0, len(sections)),
	}
	used := 0

	// First pass: include all floor sections (apply per-section cap).
	for _, s := range sections {
		if !s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		section := EvidenceAssemblySection{
			Name:          s.Name,
			BytesIncluded: len(content),
			BytesOmitted:  len(s.Content) - len(content),
			SelectedItems: []string{s.Name},
		}
		if reason != "" {
			section.TruncationReason = reason
		}
		used += len(content)
		res.Included = append(res.Included, SectionInput{
			Name: s.Name, Content: content, MinFloor: true,
		})
		res.Sections = append(res.Sections, section)
	}

	// Second pass: non-floor in priority order, fit under remaining budget.
	for _, s := range sections {
		if s.MinFloor {
			continue
		}
		content, reason := capContent(s)
		remaining := budget - used
		if len(content) <= remaining {
			used += len(content)
			res.Included = append(res.Included, SectionInput{
				Name: s.Name, Content: content,
			})
			section := EvidenceAssemblySection{
				Name:          s.Name,
				BytesIncluded: len(content),
				BytesOmitted:  len(s.Content) - len(content),
				SelectedItems: []string{s.Name},
			}
			if reason != "" {
				section.TruncationReason = reason
			}
			res.Sections = append(res.Sections, section)
			continue
		}
		// Doesn't fit even at PerSectionCap — try line-trim to fit.
		if remaining > 0 {
			trimmed := trimToLineBudget(content, remaining-len(TruncationMarker))
			if trimmed != "" {
				body := trimmed + TruncationMarker
				used += len(body)
				res.Included = append(res.Included, SectionInput{
					Name: s.Name, Content: body,
				})
				res.Sections = append(res.Sections, EvidenceAssemblySection{
					Name:             s.Name,
					BytesIncluded:    len(body),
					BytesOmitted:     len(s.Content) - len(body),
					TruncationReason: "budget",
					SelectedItems:    []string{s.Name},
				})
				continue
			}
		}
		// No room: omit entirely.
		res.Omitted = append(res.Omitted, s)
		res.Sections = append(res.Sections, EvidenceAssemblySection{
			Name:             s.Name,
			BytesIncluded:    0,
			BytesOmitted:     len(s.Content),
			TruncationReason: "budget",
			OmittedItems:     []string{s.Name},
		})
	}
	res.TotalBytes = used
	return res
}

func capContent(s SectionInput) (string, string) {
	if s.PerSectionCap <= 0 || len(s.Content) <= s.PerSectionCap {
		return s.Content, ""
	}
	clamped, truncated, _ := ClampOutput(s.Content, s.PerSectionCap)
	if truncated {
		return clamped, "per_section_cap"
	}
	return clamped, ""
}

// trimToLineBudget returns the longest prefix of s, ending on a line
// boundary, whose length is at most budget. Returns "" if budget <= 0
// or the first line alone exceeds budget.
func trimToLineBudget(s string, budget int) string {
	if budget <= 0 {
		return ""
	}
	if len(s) <= budget {
		return s
	}
	cut := strings.LastIndexByte(s[:budget], '\n')
	if cut <= 0 {
		return ""
	}
	return s[:cut+1]
}

package evidence

import "strings"

// DiffFile is one file's slice of a unified diff. Stat is the
// "+N -N" or "Bin" summary line; HunkHeaders are the "@@ ..." lines
// in original order; Body is the full per-file diff text including
// the "diff --git" header.
type DiffFile struct {
	Path        string
	Stat        string
	HunkHeaders []string
	Body        string
}

// DecomposeDiff parses a unified diff into per-file slices. It supports
// the standard "diff --git a/<path> b/<path>" delimiter produced by
// git. Files that lack a parseable header are returned with an empty
// Path. The returned slice preserves input order.
//
// FEAT-022 §1: diff decomposer returns file inventory, per-file stat
// lines, and hunk headers so large diffs can degrade to
// stat + hunk-headers only.
func DecomposeDiff(diff string) []DiffFile {
	if diff == "" {
		return nil
	}
	lines := strings.Split(diff, "\n")
	var files []DiffFile
	var cur *DiffFile

	flush := func() {
		if cur != nil {
			files = append(files, *cur)
			cur = nil
		}
	}

	for i, line := range lines {
		if strings.HasPrefix(line, "diff --git ") {
			flush()
			path := parseDiffGitPath(line)
			cur = &DiffFile{Path: path}
		}
		if cur == nil {
			continue
		}
		// Append line to body (preserve trailing newlines except final empty).
		if i < len(lines)-1 {
			cur.Body += line + "\n"
		} else {
			cur.Body += line
		}
		switch {
		case strings.HasPrefix(line, "@@ "):
			cur.HunkHeaders = append(cur.HunkHeaders, line)
		case strings.HasPrefix(line, "Binary files "):
			cur.Stat = "Bin"
		}
	}
	flush()
	return files
}

func parseDiffGitPath(header string) string {
	// "diff --git a/<path> b/<path>"
	rest := strings.TrimPrefix(header, "diff --git ")
	parts := strings.SplitN(rest, " ", 2)
	if len(parts) == 0 {
		return ""
	}
	a := parts[0]
	a = strings.TrimPrefix(a, "a/")
	return a
}

// ClampDiff bounds a unified diff to max bytes. When the diff fits, it
// returns the diff unchanged. When it does not, it degrades each file
// to "stat + hunk headers only" in input order until the budget is
// reached, then truncates the remainder. Files that don't fit at all
// are listed as omitted.
//
// FEAT-022 §1: large diffs degrade to stat + hunk-headers only.
func ClampDiff(diff string, max int) (clamped string, section EvidenceAssemblySection) {
	section = EvidenceAssemblySection{Name: "diff"}
	if len(diff) <= max {
		section.BytesIncluded = len(diff)
		return diff, section
	}
	files := DecomposeDiff(diff)
	if len(files) == 0 {
		out, truncated, orig := ClampOutput(diff, max)
		section.BytesIncluded = len(out)
		section.BytesOmitted = orig - len(out)
		if truncated {
			section.TruncationReason = "byte_cap"
		}
		return out, section
	}

	var b strings.Builder
	used := 0
	reserve := len(TruncationMarker)
	for _, f := range files {
		// Try full body first.
		if used+len(f.Body) <= max {
			b.WriteString(f.Body)
			used += len(f.Body)
			section.SelectedItems = append(section.SelectedItems, f.Path)
			continue
		}
		// Degrade: stat + hunk headers only.
		degraded := degradedFile(f)
		if used+len(degraded)+reserve <= max {
			b.WriteString(degraded)
			used += len(degraded)
			section.SelectedItems = append(section.SelectedItems, f.Path)
			section.BytesOmitted += len(f.Body) - len(degraded)
			if section.TruncationReason == "" {
				section.TruncationReason = "diff_degraded"
			}
			continue
		}
		// No room even for degraded form: omit.
		section.OmittedItems = append(section.OmittedItems, f.Path)
		section.BytesOmitted += len(f.Body)
		if section.TruncationReason == "" {
			section.TruncationReason = "byte_cap"
		}
	}
	if section.BytesOmitted > 0 {
		b.WriteString(TruncationMarker)
	}
	out := b.String()
	section.BytesIncluded = len(out)
	return out, section
}

func degradedFile(f DiffFile) string {
	var b strings.Builder
	b.WriteString("diff --git a/")
	b.WriteString(f.Path)
	b.WriteString(" b/")
	b.WriteString(f.Path)
	b.WriteString("\n")
	if f.Stat != "" {
		b.WriteString(f.Stat)
		b.WriteString("\n")
	}
	for _, h := range f.HunkHeaders {
		b.WriteString(h)
		b.WriteString("\n")
	}
	return b.String()
}

